   153→// NewBuilder returns a new LabelsBuilder.
   154→func NewBuilder(base Labels) *Builder {
   155→	b := &Builder{
   156→		del: make([]string, 0, 5),
   157→		add: make([]Label, 0, 5),
   158→	}
   159→	b.Reset(base)
   160→	return b
   161→}
   162→
   163→// Del deletes the label of the given name.
   164→func (b *Builder) Del(ns ...string) *Builder {
   165→	for _, n := range ns {
   166→		for i, a := range b.add {
   167→			if a.Name == n {
   168→				b.add = append(b.add[:i], b.add[i+1:]...)
   169→			}
   170→		}
   171→		b.del = append(b.del, n)
   172→	}
   173→	return b
   174→}
   175→
   176→// Keep removes all labels from the base except those with the given names.
   177→func (b *Builder) Keep(ns ...string) *Builder {
   178→	b.base.Range(func(l Label) {
   179→		if slices.Contains(ns, l.Name) {
   180→			return
   181→		}
   182→		b.del = append(b.del, l.Name)
   183→	})
   184→	return b
   185→}
   186→
   187→// Set the name/value pair as a label. A value of "" means delete that label.
   188→func (b *Builder) Set(n, v string) *Builder {
   189→	if v == "" {
   190→		// Empty labels are the same as missing labels.
   191→		return b.Del(n)
   192→	}
   193→	for i, a := range b.add {
   194→		if a.Name == n {
   195→			b.add[i].Value = v
   196→			return b
   197→		}
   198→	}
   199→	b.add = append(b.add, Label{Name: n, Value: v})
   200→
   201→	return b
   202→}
   203→
   204→func (b *Builder) Get(n string) string {
   205→	// Del() removes entries from .add but Set() does not remove from .del, so check .add first.
   206→	for _, a := range b.add {
   207→		if a.Name == n {
   208→			return a.Value
   209→		}
   210→	}
   211→	if slices.Contains(b.del, n) {
   212→		return ""
   213→	}
   214→	return b.base.Get(n)
   215→}
   216→
   217→// Range calls f on each label in the Builder.
   218→func (b *Builder) Range(f func(l Label)) {
   219→	// Stack-based arrays to avoid heap allocation in most cases.
   220→	var addStack [128]Label
   221→	var delStack [128]string
   222→	// Take a copy of add and del, so they are unaffected by calls to Set() or Del().
   223→	origAdd, origDel := append(addStack[:0], b.add...), append(delStack[:0], b.del...)
   224→	b.base.Range(func(l Label) {
   225→		if !slices.Contains(origDel, l.Name) && !contains(origAdd, l.Name) {
   226→			f(l)
   227→		}
   228→	})
   229→	for _, a := range origAdd {
   230→		f(a)
   231→	}
   232→}
   233→
   234→func contains(s []Label, n string) bool {
   235→	for _, a := range s {
   236→		if a.Name == n {
   237→			return true
   238→		}
   239→	}
   240→	return false
   241→}
   242→
   243→func yoloString(b []byte) string {
   244→	return unsafe.String(unsafe.SliceData(b), len(b))
   245→}
