    71→// Error prints the error message in a formatted string.
    72→func (we *WrappedError) Error() string {
    73→	if we.err == nil {
    74→		return ""
    75→	}
    76→	if we.nodeAlt != nil {
    77→		return fmt.Sprintf("%d:%d: %d:%d: %v", we.node.Line, we.node.Column, we.nodeAlt.Line, we.nodeAlt.Column, we.err)
    78→	}
    79→	if we.node != nil {
    80→		return fmt.Sprintf("%d:%d: %v", we.node.Line, we.node.Column, we.err)
    81→	}
    82→	return we.err.Error()
    83→}
