    90→// RuleGroups is a set of rule groups that are typically exposed in a file.
    91→type RuleGroups struct {
    92→	Groups []RuleGroup `yaml:"groups"`
    93→}
    94→
    95→type ruleGroups struct {
    96→	Groups []RuleGroupNode `yaml:"groups"`
