    99→// Validate validates all rules in the rule groups.
   100→func (g *RuleGroups) Validate(node ruleGroups, nameValidationScheme model.ValidationScheme, p parser.Parser) (errs []error) {
   101→	if err := namevalidationutil.CheckNameValidationScheme(nameValidationScheme); err != nil {
   102→		errs = append(errs, err)
   103→		return errs
   104→	}
   105→
   106→	set := map[string]struct{}{}
   107→
   108→	for j, g := range g.Groups {
   109→		if g.Name == "" {
   110→			errs = append(errs, fmt.Errorf("%d:%d: Groupname must not be empty", node.Groups[j].Line, node.Groups[j].Column))
   111→		}
   112→
   113→		if _, ok := set[g.Name]; ok {
   114→			errs = append(
   115→				errs,
   116→				fmt.Errorf("%d:%d: groupname: \"%s\" is repeated in the same file", node.Groups[j].Line, node.Groups[j].Column, g.Name),
   117→			)
   118→		}
   119→
   120→		for k, v := range g.Labels {
   121→			if !nameValidationScheme.IsValidLabelName(k) || k == model.MetricNameLabel {
   122→				errs = append(
   123→					errs, fmt.Errorf("invalid label name: %s", k),
   124→				)
   125→			}
   126→
   127→			if !model.LabelValue(v).IsValid() {
   128→				errs = append(
   129→					errs, fmt.Errorf("invalid label value: %s", v),
   130→				)
   131→			}
   132→		}
   133→
   134→		set[g.Name] = struct{}{}
   135→
   136→		for i, r := range g.Rules {
   137→			for _, node := range r.Validate(node.Groups[j].Rules[i], nameValidationScheme, p) {
   138→				var ruleName string
   139→				if r.Alert != "" {
   140→					ruleName = r.Alert
   141→				} else {
   142→					ruleName = r.Record
   143→				}
   144→				errs = append(errs, &Error{
   145→					Group:    g.Name,
   146→					Rule:     i + 1,
   147→					RuleName: ruleName,
   148→					Err:      node,
   149→				})
   150→			}
   151→		}
   152→	}
   153→
   154→	return errs
   155→}
